INSERT INTO prospect_pages (slug, company_name, password, html_content, is_active, view_count, created_by, created_at, updated_at) VALUES ('rootcode', 'Rootcode', 'rootcode2026', '<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Rootcode x PureBrain | Pure Technology</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  :root {
    --pt-blue: #2a93c1;
    --pt-orange: #f1420b;
    --dark: #0d0f14;
    --surface: #141820;
    --surface2: #1e2530;
    --border: #2a3040;
    --text: #e8eaf0;
    --text-dim: #8892a4;
    --text-mid: #b0bac8;
    --green: #22c55e;
    --font-heading: ''Oswald'', system-ui, sans-serif;
    --font-body: ''Inter'', system-ui, sans-serif;
    --font-mono: ''JetBrains Mono'', monospace;
  }
  body {
    background: var(--dark);
    color: var(--text);
    font-family: var(--font-body);
    font-size: 14px;
    line-height: 1.6;
    max-width: 960px;
    margin: 0 auto;
    padding: 40px 24px 80px;
  }
  @import url(''https://fonts.googleapis.com/css2?family=Oswald:wght@400;600;700&family=Inter:wght@300;400;500;600&display=swap'');

  /* ===== HEADER ===== */
  .header {
    text-align: center;
    padding-bottom: 32px;
    border-bottom: 1px solid var(--border);
    margin-bottom: 40px;
  }
  .logo-row {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 20px;
    margin-bottom: 24px;
    flex-wrap: wrap;
  }
  .logo-badge {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 10px 20px;
    font-family: var(--font-heading);
    font-size: 18px;
    font-weight: 700;
    letter-spacing: 2px;
  }
  .logo-badge.pt { color: var(--pt-blue); }
  .logo-badge.rootcode { color: var(--pt-orange); }
  .x-mark { color: var(--text-dim); font-size: 20px; }
  .header h1 {
    font-family: var(--font-heading);
    font-size: 28px;
    font-weight: 700;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: white;
    margin-bottom: 8px;
  }
  .header h1 span { color: var(--pt-orange); }
  .prepared-for {
    color: var(--text-mid);
    font-size: 15px;
    margin-bottom: 6px;
  }
  .prepared-for strong { color: var(--text); }
  .header-sub {
    color: var(--text-dim);
    font-size: 15px;
    max-width: 640px;
    margin: 0 auto;
    font-style: italic;
  }

  /* ===== STAT BAR ===== */
  .stat-bar {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 12px;
    margin-bottom: 40px;
  }
  .stat {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 18px 16px;
    text-align: center;
  }
  .stat-num {
    font-family: var(--font-heading);
    font-size: 28px;
    font-weight: 700;
    color: var(--pt-blue);
    line-height: 1;
    margin-bottom: 6px;
  }
  .stat-label {
    font-size: 11px;
    color: var(--text-dim);
    text-transform: uppercase;
    letter-spacing: 1px;
  }

  /* ===== SECTION TITLES ===== */
  .section-title {
    font-family: var(--font-heading);
    font-size: 13px;
    font-weight: 600;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: var(--pt-orange);
    margin-bottom: 16px;
    display: flex;
    align-items: center;
    gap: 10px;
  }
  .section-title::after {
    content: '''';
    flex: 1;
    height: 1px;
    background: var(--border);
  }

  /* ===== RESEARCH SECTION ===== */
  .research-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 12px;
    margin-bottom: 40px;
  }
  .research-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 20px;
  }
  .research-card.full-width {
    grid-column: 1 / -1;
  }
  .research-card h4 {
    font-family: var(--font-heading);
    font-size: 13px;
    font-weight: 600;
    letter-spacing: 1px;
    text-transform: uppercase;
    color: var(--pt-blue);
    margin-bottom: 12px;
  }
  .research-card p, .research-card li {
    font-size: 13px;
    color: var(--text-mid);
    line-height: 1.7;
  }
  .research-card ul { list-style: none; }
  .research-card li::before { content: "\2192 "; color: var(--pt-orange); }
  .research-card li { margin-bottom: 4px; }

  /* ===== VALUE PROPOSITIONS ===== */
  .value-props { display: flex; flex-direction: column; gap: 20px; margin-bottom: 40px; }
  .value-prop {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 12px;
    overflow: hidden;
  }
  .vp-header {
    padding: 20px 24px 16px;
    border-bottom: 1px solid var(--border);
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 16px;
    flex-wrap: wrap;
  }
  .vp-number {
    font-size: 10px;
    font-weight: 600;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    padding: 3px 10px;
    border-radius: 4px;
    background: rgba(42,147,193,0.1);
    color: var(--pt-blue);
    border: 1px solid rgba(42,147,193,0.3);
    white-space: nowrap;
    align-self: center;
  }
  .vp-name {
    font-family: var(--font-heading);
    font-size: 22px;
    font-weight: 700;
    letter-spacing: 1px;
    color: white;
    margin-bottom: 4px;
  }
  .vp-sub { font-size: 13px; color: var(--text-dim); }
  .vp-body {
    padding: 20px 24px;
  }
  .vp-body ul { list-style: none; }
  .vp-body li {
    font-size: 13px;
    color: var(--text-mid);
    padding: 5px 0;
    line-height: 1.6;
  }
  .vp-body li::before { content: "\2713 "; color: var(--green); }
  .vp-body li.highlight { color: var(--text); font-weight: 500; }
  .vp-body .ref {
    margin-top: 12px;
    padding-top: 12px;
    border-top: 1px solid var(--border);
    font-size: 12px;
    color: var(--text-dim);
    font-style: italic;
  }

  /* ===== LIVING PROOF BOX ===== */
  .proof-box {
    background: linear-gradient(135deg, rgba(34,197,94,0.06) 0%, rgba(42,147,193,0.08) 50%, rgba(241,66,11,0.06) 100%);
