    border-radius: 12px;
    padding: 32px;
    margin-bottom: 40px;
  }
  .proof-box h3 {
    font-family: var(--font-heading);
    font-size: 24px;
    font-weight: 700;
    letter-spacing: 1px;
    color: white;
    margin-bottom: 8px;
    text-align: center;
  }
  .proof-box .proof-subtitle {
    text-align: center;
    color: var(--text-dim);
    font-size: 14px;
