    gap: 16px;
    margin-bottom: 24px;
  }
  .proof-item {
    background: rgba(0,0,0,0.2);
    border-radius: 8px;
    padding: 20px 16px;
    text-align: center;
  }
  .proof-icon {
    font-size: 28px;
    margin-bottom: 10px;
    display: block;
  }
  .proof-label {
    font-family: var(--font-heading);
    font-size: 13px;
    font-weight: 600;
    color: var(--green);
    letter-spacing: 1px;
    text-transform: uppercase;
    margin-bottom: 6px;
  }
  .proof-desc {
    font-size: 12px;
    color: var(--text-mid);
    line-height: 1.5;
  }
  .proof-narrative {
    background: rgba(0,0,0,0.15);
    border-radius: 8px;
    padding: 20px 24px;
    font-size: 13px;
    color: var(--text-mid);
    line-height: 1.7;
    border-left: 3px solid var(--green);
  }
  .proof-narrative strong { color: var(--text); }
  .proof-cta {
    text-align: center;
    margin-top: 20px;
    font-size: 15px;
    color: var(--text);
    font-style: italic;
  }

  /* ===== CTA ===== */
  .cta-box {
    background: linear-gradient(135deg, rgba(42,147,193,0.1) 0%, rgba(241,66,11,0.08) 100%);
    border: 1px solid rgba(42,147,193,0.3);
    border-radius: 12px;
    padding: 32px;
    text-align: center;
  }
  .cta-box h3 {
    font-family: var(--font-heading);
    font-size: 24px;
    font-weight: 700;
    letter-spacing: 1px;
    color: white;
    margin-bottom: 10px;
  }
  .cta-box p { color: var(--text-dim); font-size: 14px; max-width: 500px; margin: 0 auto 20px; }
  .cta-contacts {
    display: flex;
    justify-content: center;
    gap: 32px;
    flex-wrap: wrap;
  }
  .cta-contact { font-size: 13px; color: var(--text-mid); }
  .cta-contact strong { color: var(--pt-blue); display: block; font-size: 15px; margin-bottom: 2px; }

  /* ===== FOOTER ===== */
  .footer {
    margin-top: 40px;
    text-align: center;
    font-size: 11px;
    color: var(--text-dim);
    border-top: 1px solid var(--border);
    padding-top: 20px;
  }

  @media (max-width: 700px) {
    .stat-bar { grid-template-columns: repeat(2, 1fr); }
    .research-grid { grid-template-columns: 1fr; }
    .proof-grid { grid-template-columns: 1fr; }
  }
  @media print {
    body { background: white; color: black; padding: 20px; }
    .stat, .research-card, .value-prop, .proof-box, .cta-box {
      background: #f8f8f8; border: 1px solid #ddd;
    }
  }
</style>
